const payload = $json.body;
const issue = payload.issue || {};

function normaliseStatus(statusCategory) {
  const key = statusCategory?.key || '';
  if (key === 'new') return 'todo';
  if (key === 'indeterminate') return 'in_progress';
  if (key === 'done' || key === 'complete') return 'done';
  return 'in_progress';
}

return {
  workspace_id: $env.DEFAULT_WORKSPACE_ID,
  source: 'jira',
  event_type: payload.webhookEvent,
  payload: {
    issue: {
      id: String(issue.id ?? ''),
      key: issue.key ?? '',
      summary: issue.fields?.summary ?? '',
      status: normaliseStatus(issue.fields?.status?.statusCategory),
      updated_at: issue.fields?.updated ? new Date(issue.fields.updated).toISOString() : new Date().toISOString()
    }
  },
  received_at: new Date().toISOString()
};

const payload = $json.body;
const pr = payload.pull_request || {};

return {
  workspace_id: $env.DEFAULT_WORKSPACE_ID,
  source: 'github',
  event_type: payload.action ? `pull_request.${payload.action}` : 'pull_request',
  payload: {
    number: pr.number,
    title: pr.title,
    state: pr.state,
    merged: pr.merged ?? false,
    merged_at: pr.merged_at ? new Date(pr.merged_at).toISOString() : null,
    created_at: pr.created_at ? new Date(pr.created_at).toISOString() : new Date().toISOString(),
    updated_at: pr.updated_at ? new Date(pr.updated_at).toISOString() : new Date().toISOString()
  },
  received_at: new Date().toISOString()
};
